 @Autowired SalePaymentSessionService service;@Autowired JdbcTemplate jdbc;@Autowired TransactionTemplate tx;
 @MockitoBean PosCashService sales;@MockitoBean DocumentService documents;@MockitoBean PosCardDocumentSnapshot snapshots;@MockitoBean CurrentOrganization organization;@MockitoBean CurrentTerminal currentTerminal;@MockitoBean CardTerminalConfigurationReader configurations;@MockitoBean PaymentTerminalOperationService operations;
 @Test @Transactional(propagation=Propagation.NOT_SUPPORTED) void simultaneousServiceFinalizeCreatesExactlyOneTicket()throws Exception{var company=UUID.randomUUID();var store=UUID.randomUUID();var terminal=UUID.randomUUID();var role=UUID.randomUUID();var userId=UUID.randomUUID();var warehouse=UUID.randomUUID();var cash=UUID.randomUUID();var card=UUID.randomUUID();var session=UUID.randomUUID();var allocation=UUID.randomUUID();jdbc.execute("insert into empresa(id,tax_id,razon_social,domicilio_fiscal) values ('"+company+"','B1','Test','{\"linea1\":\"x\",\"ciudad\":\"x\",\"codigoPostal\":\"1\",\"provincia\":\"x\",\"pais\":\"ES\"}')");jdbc.execute("insert into tienda(id,empresa_id,nombre,direccion,address_normalized_hash,timezone,moneda,locale,codigo_tienda) values ('"+store+"','"+company+"','T','{\"linea1\":\"x\",\"ciudad\":\"x\",\"codigoPostal\":\"1\",\"provincia\":\"x\",\"pais\":\"ES\"}','h','Europe/Madrid','EUR','es-ES','001')");jdbc.execute("insert into terminal(id,tienda_id,nombre,tipo,credential_hash) values ('"+terminal+"','"+store+"','TPV','TERMINAL_VENTA','h')");jdbc.execute("insert into rol(id,tienda_id,nombre) values ('"+role+"','"+store+"','SELLER')");jdbc.execute("insert into usuario(id,tienda_id,nombre,user_name,password_hash,rol_id) values ('"+userId+"','"+store+"','SELLER','Seller','h','"+role+"')");jdbc.execute("insert into almacen(id,tienda_id,nombre,predeterminado) values ('"+warehouse+"','"+store+"','A',true)");jdbc.execute("insert into metodo_pago(id,empresa_id,nombre) values ('"+cash+"','"+company+"','EFECTIVO'),('"+card+"','"+company+"','TARJETA')");jdbc.execute("insert into sale_payment_session(id,store_id,terminal_id,user_id,request_hash,document_snapshot,total,currency,status,created_at,updated_at) values ('"+session+"','"+store+"','"+terminal+"','"+userId+"','h','{}',1,'EUR','COVERED',now(),now())");jdbc.execute("insert into sale_payment_allocation(id,session_id,idempotency_key,kind,amount,status,created_at,updated_at) values ('"+allocation+"','"+session+"','cash','CASH',1,'APPROVED',now(),now())");var storeObj=mock(Store.class);when(storeObj.getId()).thenReturn(store);var companyObj=mock(Company.class);when(companyObj.getId()).thenReturn(company);when(organization.currentStore()).thenReturn(storeObj);when(organization.currentCompany()).thenReturn(companyObj);when(currentTerminal.terminalId(any())).thenReturn(terminal);var principal=mock(UserAccount.class);when(principal.getId()).thenReturn(userId);var auth=new UsernamePasswordAuthenticationToken(principal,"n/a");when(snapshots.deserialize("{}")).thenReturn(mock(ApprovedCardTicketSnapshot.class));when(documents.createApprovedCardTicketFromSnapshot(any(),anyList(),any())).thenAnswer(inv->{var id=UUID.randomUUID();jdbc.update("insert into documento(id,tienda_id,almacen_id,tipo,estado,numero,fecha,creado_en,creado_por,total) values (?,?,?,'TICKET','CONFIRMADO','T-1',current_date,now(),?,1)",id,store,warehouse,userId);var d=mock(CommercialDocument.class);when(d.getId()).thenReturn(id);when(d.getNumero()).thenReturn("T-1");when(d.getEstado()).thenReturn(DocumentStatus.CONFIRMADO);when(d.getConfirmadoEn()).thenReturn(Instant.now());when(d.getLineas()).thenReturn(List.of());when(d.getPagos()).thenReturn(List.of());when(d.getTotal()).thenReturn(BigDecimal.ONE);return d;});when(documents.loadForPrint(any())).thenAnswer(inv->{var d=mock(CommercialDocument.class);when(d.getId()).thenReturn(inv.getArgument(0));when(d.getNumero()).thenReturn("T-1");when(d.getEstado()).thenReturn(DocumentStatus.CONFIRMADO);when(d.getConfirmadoEn()).thenReturn(Instant.now());when(d.getLineas()).thenReturn(List.of());when(d.getPagos()).thenReturn(List.of());when(d.getTotal()).thenReturn(BigDecimal.ONE);return d;});var start=new CountDownLatch(1);try(var pool=Executors.newFixedThreadPool(2)){Callable<UUID> call=()->{start.await();return service.finalizeSession(session,auth).session().getTicketId();};var a=pool.submit(call);var b=pool.submit(call);start.countDown();assertThat(a.get(15,TimeUnit.SECONDS)).isEqualTo(b.get(15,TimeUnit.SECONDS));assertThat(jdbc.queryForObject("select count(*) from documento where numero='T-1'",Integer.class)).isEqualTo(1);verify(documents,times(1)).createApprovedCardTicketFromSnapshot(any(),anyList(),any());}}
